        const float sign_v = (interp > 0.0f) ? 1.0f : ((interp < 0.0f) ? -1.0f : 0.0f);
        float pv = p.x;
        pv = pv - lr * (sign_v + wd * pv);
        p.x = pv;
        const float ea_new = beta2 * ea_old + (1.0f - beta2) * g.x;
        exp_avg_val_x = ea_new;
    }
    // Component y
    {
        const float ea_old = exp_avg_val_y;
        const float interp = beta1 * ea_old + (1.0f - beta1) * g.y;
        const float sign_v = (interp > 0.0f) ? 1.0f : ((interp < 0.0f) ? -1.0f : 0.0f);
        float pv = p.y;
        pv = pv - lr * (sign_v + wd * pv);
        p.y = pv;
        const float ea_new = beta2 * ea_old + (1.0f - beta2) * g.y;
        exp_avg_val_y = ea_new;
    }
    // Component z
    {
        const float ea_old = exp_avg_val_z;
        const float interp = beta1 * ea_old + (1.0f - beta1) * g.z;
        const float sign_v = (interp > 0.0f) ? 1.0f : ((interp < 0.0f) ? -1.0f : 0.0f);
        float pv = p.z;
        pv = pv - lr * (sign_v + wd * pv);
        p.z = pv;
        const float ea_new = beta2 * ea_old + (1.0f - beta2) * g.z;
        exp_avg_val_z = ea_new;
    }
    // Component w
    {
        const float ea_old = exp_avg_val_w;
        const float interp = beta1 * ea_old + (1.0f - beta1) * g.w;
        const float sign_v = (interp > 0.0f) ? 1.0f : ((interp < 0.0f) ? -1.0f : 0.0f);
        float pv = p.w;
        pv = pv - lr * (sign_v + wd * pv);
        p.w = pv;
        const float ea_new = beta2 * ea_old + (1.0f - beta2) * g.w;
        exp_avg_val_w = ea_new;
    }
}

void launch_lion_step_moe_q4_vec4(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor active_mask,
    float lr,
    float beta1,
    float beta2,
    float wd,
    int global_step
) {
    const int N = param.numel();
    if (N == 0) return;

    const int N4 = N / 4;
    const int grid = (N4 + 256 - 1) / 256;
    lion_step_moe_q4_vec4_kernel<<<grid, 256>>>(
        reinterpret_cast<float4*>(param.data_ptr<float>()),
        reinterpret_cast<const float4*>(grad.data_ptr<float>()),
        exp_avg_q.data_ptr<int8_t>(),
        exp_avg_scales.data_ptr<float>(),
        active_mask.data_ptr<bool>(),
        lr,
        beta1,
        beta2,
        wd,
        static_cast<unsigned>(global_step),
        N4);
}


